<template>
    <div id="box">
        <Header title="登录" v-if="!ifWx" />
        <div class="mainBox">
            <SubHeader subTitle="欢迎来到诺信学院" />
            <van-form class="main" validate-first  >
                <van-field
                        v-model="state.mobile"
                        type="tel"
                        label=""
                        clearable
                        placeholder="请输入手机号"
                        :rules="[
                        { required: true, message: '请填写验证码' },
                        { pattern: /^1[3456789]\d{9}$/, message: '手机号格式不正确' }
                    ]"

                />
                <van-field
                        v-model="state.verifyCode"
                        center
                        type="digit"
                        clearable
                        label=""
                        placeholder="请输入验证码"
                        :rules="[{ required: true, message: '获取验证码' }]"
                >
                    <template #button>
                        <van-button size="small" type="primary" @click="sendverifyCode" :disabled="state.mobile.replace(/(^\s*)|(\s*$)/ig, '').length !== 11"> {{state.verifyCodeText}}</van-button>
                    </template>
                </van-field>
                <div class="subBtnBox">
                    <van-button  block type="primary"  @click="onSubmit" >登录</van-button>
                </div>
            </van-form>
        </div>
        <Footer/>
    </div>
</template>
<script>
import Header from '@/components/Header'
import Footer from '@/components/Footer'
import SubHeader from '@/components/SubHeader'
import { reactive } from 'vue'
import { useStore, mapMutations } from 'vuex'
import useIfWx from '../../mixin/useIfWx'
export default {
    setup() {
        const { ifWx } = useIfWx()
        const state = reactive({
            mobile: '',
            verifyCode: '',
            verifyCodeText: '发送验证码'
        })
        return {
            ifWx,
            state,
            store: useStore()
        }
    },
    components: {
        Header, Footer, SubHeader
    },
    mounted() {
    },
    methods: {
        ...mapMutations([
            'setCellphone'
        ]),
        // 提交
        async onSubmit() {
            if (this.state.stateMentText && !this.state.ifAgree) {
                this.$notify({ type: 'warning', message: '请确定阅读并同意用户协议' })
                return
            }
            const { mobile, verifyCode } = this.state
            // 校验验证码
            await this.Ajax('checkCode', 'post', {}, { mobile, verifyCode })
            this.store.commit('setCellphone', mobile)
            this.$notify({ type: 'success', message: '登录成功' })
            this.$router.push({
                name: 'question_checkpwd',
                query: this.route.query
            })
        },
        async sendverifyCode() {
            const state = this.state
            if (!state.timer) {
                let { mobile } = state
                mobile = mobile.toString()
                if (!mobile) {
                    this.$notify({ type: 'danger', message: '手机号不能为空' })
                    return
                }
                mobile = mobile.replace(/(^\s*)|(\s*$)/ig, '')
                if (!/^1[3456789]\d{9}$/.test(mobile)) {
                    this.$notify({ type: 'danger', message: '手机号格式不正确' })
                    return
                }
                // 可以发送验证码
                var count = 60
                state.timer = setInterval(() => {
                    count--
                    state.verifyCodeText = count + '秒'
                    if (count <= 0) {
                        clearInterval(state.timer)
                        state.timer = null
                        state.verifyCodeText = '重新发送'
                    }
                }, 1000)
                await this.Ajax('sendCode', 'post', { mobile }, null)
                this.$notify({ type: 'success', message: '验证码发送成功' })
            }
        }
    }
}
</script>

<style lang="less" scoped>
    .subBtnBox{
        margin-top: 70px;
    }
    .van-cell{
        padding-left: 0;
        padding-right: 0;
        border-bottom: 1px solid #EAEEF2;
    }
</style>

